import{_ as o,o as t,c as i,aj as r}from"./chunks/framework.DEEoir6m.js";const g=JSON.parse('{"title":"Changelog","description":"Historique des versions GISPulse.","frontmatter":{"title":"Changelog","description":"Historique des versions GISPulse."},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),a={name:"changelog.md"};function s(c,e,l,n,d,u){return t(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>Toutes les modifications notables sont documentées ici. Format basé sur <a href="https://keepachangelog.com/fr/1.1.0/" target="_blank" rel="noreferrer">Keep a Changelog</a>. Versionnement <a href="https://semver.org/lang/fr/" target="_blank" rel="noreferrer">Semantic Versioning</a>.</p><h2 id="unreleased" tabindex="-1">[Unreleased] <a class="header-anchor" href="#unreleased" aria-label="Permalink to &quot;[Unreleased]&quot;">​</a></h2><h3 id="changements" tabindex="-1">Changements <a class="header-anchor" href="#changements" aria-label="Permalink to &quot;Changements&quot;">​</a></h3><ul><li><strong>Doc capabilities</strong> — passe de <strong>78 à 117</strong> capabilities documentées (FR + EN), 11 → 18 catégories. Ajout des sections : overlay &amp; combinaison, manipulation d&#39;attributs, pivot/unpivot, sélection ordonnée &amp; échantillonnage, multipart &amp; dimensions Z/M, transformations géométriques, frontière &amp; projection, temporel, 3D pointcloud.</li><li><strong>Playground manifest</strong> — régénération avec les <strong>6 scénarios</strong> réellement déployés (S1 flood-risk, S2 data-quality, S3 accessibility, S4 road-setback, S5 green-spaces, S6 real-estate). L&#39;ancien manifeste ne listait que <code>road-setback</code>.</li><li><strong>Build playground idempotent</strong> — <code>scripts/build_playground_data.py</code> : nouvelle fonction <code>_entry_from_disk</code> qui émet une entrée manifest depuis les fichiers existants quand le GPKG source est absent.</li></ul><h3 id="corrections" tabindex="-1">Corrections <a class="header-anchor" href="#corrections" aria-label="Permalink to &quot;Corrections&quot;">​</a></h3><ul><li><strong>CHANGELOG v1.1.0</strong> — corrigé : S5 décrit comme « Park accessibility » (et non « Canopy typology »), mention du « S7 / seven-scenario index » retirée car jamais livrée.</li><li><strong>Pages orphelines</strong> — <code>playground/environmental-ndvi.md</code> (FR + EN) supprimées : redirections JS dépréciées, plus aucune référence source.</li></ul><h3 id="suppressions" tabindex="-1">Suppressions <a class="header-anchor" href="#suppressions" aria-label="Permalink to &quot;Suppressions&quot;">​</a></h3><ul><li><strong>Scénario S7 dvf-heavy-tail</strong> — spec retirée du build script ; le dossier de données orphelin a été supprimé. La page n&#39;avait jamais été créée côté docs.</li></ul><hr><h2 id="_1-1-1-—-2026-04-25" tabindex="-1">[1.1.1] — 2026-04-25 <a class="header-anchor" href="#_1-1-1-—-2026-04-25" aria-label="Permalink to &quot;[1.1.1] — 2026-04-25&quot;">​</a></h2><h3 id="ajouts" tabindex="-1">Ajouts <a class="header-anchor" href="#ajouts" aria-label="Permalink to &quot;Ajouts&quot;">​</a></h3><ul><li><strong><code>capabilities/vector/</code></strong> — le monolithe <code>vector.py</code> (4 359 LOC, 43 capabilities) a été éclaté en un package de 32 sous-modules par domaine. La surface publique est préservée via shim de re-export ; tous les <code>from capabilities.vector import ...</code> continuent de fonctionner.</li></ul><h3 id="changements-1" tabindex="-1">Changements <a class="header-anchor" href="#changements-1" aria-label="Permalink to &quot;Changements&quot;">​</a></h3><ul><li><strong><code>gispulse/__init__.py</code></strong> — <code>__version__</code> fallback passe de <code>&quot;1.0.0&quot;</code> codé en dur à <code>&quot;unknown&quot;</code> quand <code>importlib.metadata</code> n&#39;est pas disponible.</li><li><strong><code>portal/package.json</code></strong> + <strong><code>docs-site/package.json</code></strong> — versions synchronisées sur <code>1.1.1</code> pour matcher <code>pyproject.toml</code>.</li></ul><h3 id="corrections-1" tabindex="-1">Corrections <a class="header-anchor" href="#corrections-1" aria-label="Permalink to &quot;Corrections&quot;">​</a></h3><ul><li><strong>Accessibilité</strong> — navigation clavier sur <code>PipelinePanel</code>, imports portail unifiés sur les tokens du design system.</li></ul><hr><h2 id="_1-1-0-—-2026-04-25" tabindex="-1">[1.1.0] — 2026-04-25 <a class="header-anchor" href="#_1-1-0-—-2026-04-25" aria-label="Permalink to &quot;[1.1.0] — 2026-04-25&quot;">​</a></h2><h3 id="ajouts-1" tabindex="-1">Ajouts <a class="header-anchor" href="#ajouts-1" aria-label="Permalink to &quot;Ajouts&quot;">​</a></h3><ul><li><strong>Playground scenarios</strong> — S5 Accessibilité aux parcs (Versailles, BD TOPO végétation ≥ 1 ha + <code>nearest_neighbor</code> + <code>classify</code>, cron hebdomadaire) et S6 Carte du prix au m² DVF (8 étapes, fishnet 50 m, palette YlOrRd quintiles).</li><li><strong>Capabilities — classification &amp; stats</strong> — <code>head_tail_breaks</code> (Jiang 2013), <code>normalize</code> (log1p / minmax / zscore), <code>grid_create</code>, <code>hexgrid_create</code>, <code>spatial_aggregate</code>, <code>classify_categorical</code>, <code>bivariate_choropleth</code>, <code>graduated_size</code>, <code>continuous_ramp</code>, <code>kde_heatmap</code>. Clustering : <code>cluster_kmeans</code>, <code>cluster_dbscan</code>, <code>cluster_hdbscan</code>, <code>morans_i</code>, <code>getis_ord_g</code>, <code>nearest_neighbor</code>, <code>od_matrix</code>, <code>spatial_weights</code>.</li><li><strong>Capabilities — 3D pointcloud</strong> — sprint LAS / LAZ : <code>pointcloud_load_las</code>, <code>pointcloud_filter_classification</code>, <code>pointcloud_zonal_height</code>, <code>pointcloud_grid_summary</code>.</li><li><strong>Capabilities — manipulation de couches P0-P3</strong> — overlay (<code>overlay_intersection</code>, <code>overlay_union</code>, <code>erase</code>), sélection (<code>sort</code>, <code>deduplicate</code>, <code>random_sample</code>, <code>top_n</code>), shape ops, transformations (<code>affine_transform</code>, <code>swap_xy</code>, <code>reverse_lines</code>), Z/M (<code>add_z</code>, <code>drop_z</code>, <code>add_m</code>, <code>drop_m</code>), pivot/unpivot, <code>classify_by_ring</code>, <code>merge_layers</code>, attribute logic (<code>add_field</code>, <code>drop_field</code>, <code>select_columns</code>, <code>rename_field</code>, <code>cast_field</code>, <code>attribute_join</code>, <code>lookup_table</code>, <code>coalesce_fields</code>, <code>case_when</code>), temporal (<code>temporal_filter</code>, <code>temporal_join</code>).</li><li><strong>Playground UX</strong> — dessin rubber band avec snap-to-close + raccourcis clavier + mesure live sur la carte ; styling intersection polygone côté client (S4 road-setback).</li><li><strong>DVF Etalab 2022-2024</strong> — dataset bundlé dans <code>examples/prepare_playground_data.py --city versailles</code> (couche <code>dvf_ventes</code>).</li><li><strong>Style sidecars</strong> — fichiers <code>.style.qml</code> / <code>.style.sld</code> / <code>.legend.json</code> émis à côté des sorties vecteur pour import direct dans QGIS / GeoServer.</li><li><strong>SQL preview</strong> — gate d&#39;authentification explicite + blocklist de capabilities sur la capability PostGIS SQL.</li></ul><h3 id="changements-2" tabindex="-1">Changements <a class="header-anchor" href="#changements-2" aria-label="Permalink to &quot;Changements&quot;">​</a></h3><ul><li><strong><code>core/config.py</code></strong> — centralisation de toutes les variables d&#39;environnement dans un module Pydantic Settings unique (13 groupes : <code>engine</code>, <code>database</code>, <code>storage</code>, <code>s3</code>, <code>api</code>, <code>oidc</code>, <code>session</code>, <code>redis</code>, <code>logging</code>, <code>audit</code>, <code>stripe</code>, <code>telemetry</code>, <code>jobs</code>). Rétro-compatible avec tous les noms <code>GISPULSE_*</code> existants.</li><li><strong>Moteur par défaut</strong> — passe de <code>duckdb</code> à <code>gpkg</code> (mode portable GPKG / GeoPandas).</li><li><strong>Suppression des <code>os.environ.get()</code> éparpillés</strong> — routers, adapters, persistence : tout passe par <code>settings</code>.</li><li><strong>Playground S5</strong> réécrit en accessibilité aux parcs par bâtiment — végétation BD TOPO ≥ 1 ha (SCoT IdF), <code>nearest_neighbor</code> distance bâti → parc, classification contre les seuils OMS / SCoT / ADEME (300 / 600 / 1000 m). L&#39;ancien trigger NDVI / canopée a été retiré.</li><li><strong>Playground S6</strong> étendu au fishnet 250 m puis resserré à 50 m pour une heatmap haute résolution.</li><li><strong>Playground S3</strong> — pipeline 6 étapes ramené à 3 via <code>cost_budgets</code> + <code>classify_by_ring</code> (4 isochrones concentriques 500 / 750 / 1000 / 1500 m).</li><li><strong><code>adapters/http</code></strong> — fork namespace résolu : arborescence legacy supprimée, entrypoints prod basculés sur <code>gispulse.adapters.http.app</code>.</li><li><strong>Sécurité</strong> — <code>MD5</code> remplacé par <code>BLAKE2b</code>, <code>eval</code> sandboxé pour <code>np</code>, <code>_ensure_valid</code> restauré.</li></ul><h3 id="corrections-2" tabindex="-1">Corrections <a class="header-anchor" href="#corrections-2" aria-label="Permalink to &quot;Corrections&quot;">​</a></h3><ul><li><strong>Capabilities — 4 P0 fermés</strong> : <code>force_geometry_type</code> (cible GeometryCollection), <code>attribute_join</code> sur DataFrame nu, NaN crash dans <code>add_z</code> / <code>add_m</code> chemin <code>from_column</code>, <code>singleparts_to_multipart</code> (perte silencieuse sur types geom mixtes).</li><li><strong>Capabilities</strong> — pointcloud grid 2D NaN, KDE grid blow-up, sandbox RCE de <code>Calculate</code>.</li><li><strong>Tests</strong> — 27 tests ressuscités après déblocage du CI, <code>__init__.py</code> shadow supprimé, <code>asyncio_mode = &quot;auto&quot;</code> activé, SyntaxError <code>workflows/ftth_network_analysis.py</code> corrigée. 3 600+ tests au vert.</li><li><strong>Tests</strong> — isolation des mutations <code>GISPULSE_ENGINE</code> ; conftest auth-disabled-by-default.</li><li><strong>Billing</strong> — <code>StripeSettings</code> par défaut + messages d&#39;erreur actionnables quand les clés Stripe manquent.</li><li><strong>Capabilities</strong> — <code>clip</code> / <code>intersects</code> : évite la vérification truth-value sur <code>GeoDataFrame</code> ; <code>spatial_predicate</code> fallback rendu explicite.</li><li><strong>Playground</strong> — S6 <code>drop_price_outliers</code> renommé <code>drop_value_outliers</code> (filtre sur <code>valeur_fonciere</code> brut, pas le prix au m²).</li><li><strong>i18n</strong> — strings <code>PipelinePanel</code> ; alignement du moteur par défaut ; pipelines <code>ref_layers</code> plural.</li><li><strong>Performance</strong> — <code>DualMapView</code> lazy-loadé.</li><li><strong>Rules router</strong> — validation du payload avant persistance (400 avec erreurs structurées).</li></ul><hr><h2 id="_1-0-2-—-sprint-s1→s6-2026-04-12" tabindex="-1">[1.0.2] — Sprint S1→S6 (2026-04-12) <a class="header-anchor" href="#_1-0-2-—-sprint-s1→s6-2026-04-12" aria-label="Permalink to &quot;[1.0.2] — Sprint S1→S6 (2026-04-12)&quot;">​</a></h2><p>Six sprints d&#39;audit et hardening : securite, architecture, tests, observabilite, couverture routers, metriques Prometheus.</p><h3 id="ajouts-2" tabindex="-1">Ajouts <a class="header-anchor" href="#ajouts-2" aria-label="Permalink to &quot;Ajouts&quot;">​</a></h3><h4 id="architecture-—-grammaire-declarative-v2-sprint-s1" tabindex="-1">Architecture — Grammaire déclarative v2 (Sprint S1) <a class="header-anchor" href="#architecture-—-grammaire-declarative-v2-sprint-s1" aria-label="Permalink to &quot;Architecture — Grammaire déclarative v2 (Sprint S1)&quot;">​</a></h4><ul><li><strong><code>PipelineSpec</code> / <code>StepSpec</code> / <code>TriggerSpec</code></strong> — grammaire unifiée remplaçant 3 DSLs divergents (rules, triggers, graph)</li><li><strong>Support DAG</strong> — les steps peuvent référencer d&#39;autres steps via <code>step.input</code></li><li><strong>Steps conditionnels</strong> — évaluation de prédicats <code>step.when</code> sur le GeoDataFrame courant</li><li><strong>Triggers inline</strong> — syntaxe <code>on/when/then</code> dans le pipeline</li><li><strong>Rétro-compatible</strong> — les pipelines v1 (flat rule lists) sont auto-convertis en v2</li><li><strong><code>PipelineExecutor</code></strong> — exécuteur unifié (mode linéaire et mode DAG via <code>GraphExecutor</code>), remplace le choix entre <code>SessionManager</code>/<code>JobRunner</code>/<code>ScenarioRunner</code></li><li><strong><code>PluginRegistry[T]</code></strong> — registre générique thread-safe avec découverte par entry points</li><li><strong><code>BoundedLayerCache</code></strong> — cache LRU extrait de <code>app.py</code> vers <code>core/cache.py</code></li><li><strong><code>ProductionAuthMiddleware</code></strong> — extrait de <code>create_app()</code> vers <code>middleware/production_auth.py</code></li></ul><h4 id="pipeline-v2-api-sprint-s2" tabindex="-1">Pipeline v2 API (Sprint S2) <a class="header-anchor" href="#pipeline-v2-api-sprint-s2" aria-label="Permalink to &quot;Pipeline v2 API (Sprint S2)&quot;">​</a></h4><ul><li><strong><code>POST /api/pipelines/execute</code></strong> — exécution de pipelines v2 avec <code>PipelineSpec</code> JSON</li><li><strong><code>POST /api/pipelines/validate</code></strong> — validation dry-run d&#39;un pipeline</li><li><strong><code>GET /api/pipelines/examples</code></strong> — exemples de pipelines v2</li><li><strong>CRUD <code>/api/triggers/{id}/operations</code></strong> — persistance des opérations spatiales dans les triggers</li><li><strong><code>SessionManager.run_pipeline_v2()</code></strong> — délègue nativement au <code>PipelineExecutor</code></li><li><strong>TypedDict pour 10 capabilities</strong> — <code>FilterParams</code>, <code>BufferParams</code>, etc. dans <code>core/capability_params.py</code></li><li><strong>PipelineEditor</strong> — mode éditeur dans le Portal : import/export JSON v2, exécution via <code>/pipelines/execute</code></li></ul><h4 id="portal-—-decomposition-et-websocket-sprint-s3" tabindex="-1">Portal — Décomposition et WebSocket (Sprint S3) <a class="header-anchor" href="#portal-—-decomposition-et-websocket-sprint-s3" aria-label="Permalink to &quot;Portal — Décomposition et WebSocket (Sprint S3)&quot;">​</a></h4><ul><li><strong><code>LayerItemButton</code></strong> (275L) et <strong><code>DatasetItem</code></strong> (150L) extraits de <code>LeftPanel.tsx</code> (1183→774 lignes)</li><li><strong>WebSocket listener</strong> remplace le polling <code>setInterval</code> dans <code>transformStore</code></li><li><strong>CI GitHub Actions</strong> — workflow <code>ci.yml</code> avec backend (pytest, ruff) et frontend (tsc, vite build)</li></ul><h4 id="documentation-et-outillage-sprint-s4" tabindex="-1">Documentation et outillage (Sprint S4) <a class="header-anchor" href="#documentation-et-outillage-sprint-s4" aria-label="Permalink to &quot;Documentation et outillage (Sprint S4)&quot;">​</a></h4><ul><li><strong><code>scripts/export_openapi.py</code></strong> — génère <code>docs/openapi.json</code> + <code>docs/API_REFERENCE.md</code> automatiquement, commande <code>make docs</code></li><li><strong>QUICKSTART.md</strong>, <strong>RULES_GUIDE.md</strong>, <strong>TRIGGERS_GUIDE.md</strong>, <strong>API_QUICKSTART.md</strong> — 4 guides utilisateur</li><li><strong><code>docs/openapi.json</code></strong> — spécification OpenAPI 3.1 complète (88 endpoints)</li></ul><h3 id="changements-3" tabindex="-1">Changements <a class="header-anchor" href="#changements-3" aria-label="Permalink to &quot;Changements&quot;">​</a></h3><h4 id="modeles-sprint-s1" tabindex="-1">Modèles (Sprint S1) <a class="header-anchor" href="#modeles-sprint-s1" aria-label="Permalink to &quot;Modèles (Sprint S1)&quot;">​</a></h4><ul><li><strong><code>core/models.py</code> scindé</strong> (795→280L) en 6 modules : <code>enums.py</code>, <code>conditions.py</code>, <code>predicates.py</code>, <code>graph.py</code>, <code>relations.py</code>, <code>session.py</code></li><li><strong><code>Rule.order</code></strong> extrait du bag <code>config</code> vers un champ dédié</li><li>Réexports backward-compatible — zéro changement d&#39;import dans le code existant</li></ul><h4 id="portal-sprint-s3" tabindex="-1">Portal (Sprint S3) <a class="header-anchor" href="#portal-sprint-s3" aria-label="Permalink to &quot;Portal (Sprint S3)&quot;">​</a></h4><ul><li><strong>Renommage types de prédicats</strong> — suppression du suffixe <code>*Node</code> (<code>AttrPredicateNode</code> → <code>AttrPredicate</code>, etc.)</li><li><strong>Forge operations connectées</strong> — <code>OperationExecutor</code> → ESB : actions <code>RUN_SQL</code> exécutées end-to-end</li></ul><h3 id="supprimes" tabindex="-1">Supprimés <a class="header-anchor" href="#supprimes" aria-label="Permalink to &quot;Supprimés&quot;">​</a></h3><ul><li><strong>Stubs clients non fonctionnels</strong> — <code>clients/qgis/</code>, <code>clients/arcgis/</code>, <code>clients/desktop/</code> (code conservé dans l&#39;historique Git)</li><li><strong>ESB <code>CircuitBreaker</code> et <code>DeadLetterQueue</code></strong> marqués <code>EXPERIMENTAL</code>, lazy-import uniquement</li></ul><h3 id="securite-sprint-s1" tabindex="-1">Securite (Sprint S1) <a class="header-anchor" href="#securite-sprint-s1" aria-label="Permalink to &quot;Securite (Sprint S1)&quot;">​</a></h3><ul><li>Patch de 13 vulnerabilites critiques (7 injections SQL, 2 RCE, 1 auth bypass)</li><li>114 tests de securite couvrant tous les vecteurs d&#39;audit</li><li><strong><code>hmac.compare_digest()</code></strong> pour toutes les comparaisons d&#39;authentification (timing-safe)</li><li><strong>Headers de securite Nginx</strong> — CSP, X-Frame-Options DENY, X-Content-Type-Options nosniff, Referrer-Policy</li><li><strong>Rate limiting</strong> sur <code>/api/filter/preview</code> (30/min) et <code>/api/filter/apply</code> (20/min)</li><li><strong><code>pip-audit</code></strong> bloque maintenant le CI sur les CVEs connues (suppression du <code>|| true</code>)</li><li><strong>Validation GISPULSE_MAX_UPLOAD_MB</strong> — gestion des valeurs invalides, cap a 5GB</li></ul><h3 id="architecture-sprint-s2" tabindex="-1">Architecture (Sprint S2) <a class="header-anchor" href="#architecture-sprint-s2" aria-label="Permalink to &quot;Architecture (Sprint S2)&quot;">​</a></h3><ul><li><strong>Migration structlog</strong> — remplacement de <code>print()</code> et <code>logging</code> par structlog dans ESB workers et pg_notify</li><li><strong>Logging des exceptions silencieuses</strong> — 6 handlers <code>except: pass</code> remplacés par <code>log.debug()</code>/<code>log.warning()</code></li><li><strong>Fix race condition jobs</strong> — vérification d&#39;annulation AVANT persistance des résultats</li><li><strong>Timeout dataset loading</strong> — 300s max pour éviter les blocages sur gros fichiers</li><li><strong>Fix collision triggers</strong> — utilisation de l&#39;UUID du trigger comme suffixe (supporte plusieurs triggers par table)</li><li><strong>Limite WebSocket</strong> — 1MB max par message sortant</li></ul><h3 id="observabilite-sprint-s4-s6" tabindex="-1">Observabilite (Sprint S4 + S6) <a class="header-anchor" href="#observabilite-sprint-s4-s6" aria-label="Permalink to &quot;Observabilite (Sprint S4 + S6)&quot;">​</a></h3><ul><li><strong><code>MetricsMiddleware</code></strong> — métriques HTTP automatiques : <code>gispulse_http_requests_total</code> (par method/path/status), <code>gispulse_http_request_duration_seconds</code>, <code>gispulse_http_requests_in_flight</code></li><li><strong>Normalisation de chemin</strong> — remplacement des UUIDs et segments numériques pour réduire la cardinalité Prometheus</li><li><strong>Trace ID correlation</strong> — <code>_log.error(&quot;unhandled_exception&quot;, trace_id=...)</code> dans le error handler</li><li><strong>Migration jobs_router</strong> — stdlib <code>logging</code> remplacé par structlog avec keyword args</li><li><strong>Docker non-root</strong> — <code>USER appuser</code> (uid 1000) dans le Dockerfile</li><li><strong><code>.dockerignore</code></strong> — exclut .git, node_modules, tests, docs, .env, IDE files</li><li><strong><code>.pre-commit-config.yaml</code></strong> — ruff lint+format, trailing whitespace, YAML check, détection de clés privées</li></ul><h3 id="tests-sprints-s3-s5" tabindex="-1">Tests (Sprints S3 + S5) <a class="header-anchor" href="#tests-sprints-s3-s5" aria-label="Permalink to &quot;Tests (Sprints S3 + S5)&quot;">​</a></h3><ul><li><strong>2 439 tests</strong> passent (contre 2 205 en v1.0.1), +234 tests ajoutés sur 6 sprints</li><li><strong>106 fichiers de tests</strong> (unitaires + intégration + sécurité)</li><li><strong>Couverture routers : 85%</strong> (23/27 routers testés, contre 33% avant)</li><li>Nouveaux fichiers : <code>test_rules_router</code>, <code>test_triggers_router</code>, <code>test_jobs_router</code>, <code>test_datasets_router</code>, <code>test_cli</code>, <code>test_persistence_io</code>, <code>test_auth_router</code>, <code>test_admin_router</code>, <code>test_scenarios_router</code>, <code>test_schedules_router</code>, <code>test_catalog_router</code>, <code>test_relations_router</code>, <code>test_filter_router</code>, <code>test_portal_datasets_router</code>, <code>test_esb_router</code>, <code>test_tiles_router</code></li><li><strong>CI : mypy</strong> (type checking core modules) + <strong>ESLint/Vitest</strong> (frontend lint + tests)</li><li>90 fichiers de tests (unitaires + intégration + sécurité)</li></ul><hr><h2 id="_1-0-0-—-2026-04-06" tabindex="-1">[1.0.0] — 2026-04-06 <a class="header-anchor" href="#_1-0-0-—-2026-04-06" aria-label="Permalink to &quot;[1.0.0] — 2026-04-06&quot;">​</a></h2><p>Release initiale publique. 27 capabilities, 1 836 tests, moteur multi-backend DuckDB/PostGIS.</p><hr><h2 id="_0-1-0-—-2026-03-31" tabindex="-1">[0.1.0] — 2026-03-31 <a class="header-anchor" href="#_0-1-0-—-2026-03-31" aria-label="Permalink to &quot;[0.1.0] — 2026-03-31&quot;">​</a></h2><h3 id="ajouts-3" tabindex="-1">Ajouts <a class="header-anchor" href="#ajouts-3" aria-label="Permalink to &quot;Ajouts&quot;">​</a></h3><h4 id="moteur-central" tabindex="-1">Moteur central <a class="header-anchor" href="#moteur-central" aria-label="Permalink to &quot;Moteur central&quot;">​</a></h4><ul><li>Moteur geospatial DuckDB avec modes portable SpatiaLite et persistant PostGIS</li><li><code>SessionManager</code> avec pipeline E2E, pattern <code>ExecutionStrategy</code>, support session SpatiaLite</li><li><code>JobRunner</code> avec exécution asynchrone et suivi de statut des jobs</li><li>Opérations cross-layer : spatial join, système de layer de référence, support multi-layer</li><li>Pagination, association datasets, CRUD projets</li><li>Migration PyOGRIO pour I/O multi-format</li><li>Robustification edge cases : zones shadow, centroïde, capabilities surface/longueur</li><li>Support GeoParquet et serveur OGC avec serveur de tuiles MVT</li></ul><h4 id="cli" tabindex="-1">CLI <a class="header-anchor" href="#cli" aria-label="Permalink to &quot;CLI&quot;">​</a></h4><ul><li>Entry point CLI Typer (<code>gispulse</code>)</li><li>Commandes : <code>init</code>, <code>validate</code>, <code>info</code>, <code>layers</code>, <code>formats</code>, <code>capabilities</code>, <code>serve</code>, <code>portal</code>, <code>doctor</code></li><li>Acceptance multi-format via la couche I/O intégrée</li></ul><h4 id="capabilities-vectorielles-10" tabindex="-1">Capabilities vectorielles (10) <a class="header-anchor" href="#capabilities-vectorielles-10" aria-label="Permalink to &quot;Capabilities vectorielles (10)&quot;">​</a></h4><ul><li><code>buffer</code> — buffer métrique avec reprojection automatique</li><li><code>union</code> — fusion de toutes les features</li><li><code>reproject</code> — reprojection CRS</li><li><code>filter</code> — filtre attributaire</li><li><code>clip</code> — découpe par layer de référence</li><li><code>intersects</code> — filtre par intersection spatiale</li><li><code>spatial_join</code> — jointure spatiale</li><li><code>centroid</code> — extraction des centroïdes</li><li><code>area_length</code> — calcul surface et longueur</li><li><code>dissolve</code> — dissolution par attribut</li><li>Registre de capabilities avec auto-découverte</li><li>Injection de capabilities lifespan-managed</li></ul><h4 id="regles" tabindex="-1">Règles <a class="header-anchor" href="#regles" aria-label="Permalink to &quot;Règles&quot;">​</a></h4><ul><li>Système rules-as-config avec définitions JSON</li><li>Rule editor UI avec predicate builder</li><li>Évaluation de règles basée sur triggers avec <code>auto_eval</code> et SSE eval-stream</li></ul><h4 id="persistence" tabindex="-1">Persistence <a class="header-anchor" href="#persistence" aria-label="Permalink to &quot;Persistence&quot;">​</a></h4><ul><li>Mode PostGIS persistant avec live sync et intégration pg_notify</li><li>Mode SpatiaLite portable (session niveau 2, serverless)</li><li>Export GPKG depuis le catalogue</li><li>Scene manager avec snapshot et restore</li></ul><h4 id="api-rest-fastapi" tabindex="-1">API REST (FastAPI) <a class="header-anchor" href="#api-rest-fastapi" aria-label="Permalink to &quot;API REST (FastAPI)&quot;">​</a></h4><ul><li>API REST complète : projets, datasets, features, sessions, règles, triggers, scénarios</li><li>14 routeurs, 100+ endpoints</li><li>Mise à jour de features, exécution SQL, endpoints relations</li><li>Endpoints d&#39;ingestion OGC Features</li><li>Streaming SSE pour les résultats d&#39;évaluation de triggers</li><li>Configuration hot-reload Docker pour API et Portal dev servers</li><li>Error handlers globaux <code>{&quot;error&quot;: {&quot;code&quot;, &quot;message&quot;, &quot;detail&quot;}}</code> pour 400/404/422/500</li></ul><h4 id="portal-react-19" tabindex="-1">Portal (React 19) <a class="header-anchor" href="#portal-react-19" aria-label="Permalink to &quot;Portal (React 19)&quot;">​</a></h4><ul><li>Layout 5 workspaces : Explorer, Map, Workflows, Catalog, Data</li><li>Layer tree avec groupes, color picker, légende et symbologie</li><li>Layout de panneaux redimensionnables avec ActivityBar et Inspector</li><li>Node editor (XyFlow/ReactFlow v12) avec 9 types de nœuds, NodePalette, inspector inline</li><li>Trigger stepper, barre de scénarios, UI opérations spatiales</li><li>Console SQL et inspecteur de features</li><li>Workspace Catalog avec cartes, favoris, mini-map, filtrage domaine</li><li>Dark mode avec tokens design OKLCH, police Geist, notifications toast</li><li>Palette de commandes (Ctrl+K), raccourcis clavier (1–5, Ctrl+I/B/K/S/?)</li><li>Upload drag-and-drop et import URL, export GPKG avec styles QML</li></ul><h4 id="viewer" tabindex="-1">Viewer <a class="header-anchor" href="#viewer" aria-label="Permalink to &quot;Viewer&quot;">​</a></h4><ul><li>Viewer spatial deck.gl embarqué servi via <code>gispulse serve</code></li></ul><h4 id="esb-triggers" tabindex="-1">ESB / Triggers <a class="header-anchor" href="#esb-triggers" aria-label="Permalink to &quot;ESB / Triggers&quot;">​</a></h4><ul><li>Bus d&#39;événements avec pg_notify, routage, circuit breaker, dead letter queue</li><li>Trigger Builder UI avec composition de prédicats</li><li><code>SessionProvisioner</code> avec <code>TriggerEvaluator</code> et SSE eval-stream</li></ul><h4 id="catalogue" tabindex="-1">Catalogue <a class="header-anchor" href="#catalogue" aria-label="Permalink to &quot;Catalogue&quot;">​</a></h4><ul><li>Catalogue de données GIS : projections, fonds de carte, flux WMS/WFS, sources open data</li></ul><h4 id="tests" tabindex="-1">Tests <a class="header-anchor" href="#tests" aria-label="Permalink to &quot;Tests&quot;">​</a></h4><ul><li>46 fichiers de tests : unitaires et intégration</li><li>Tests d&#39;intégration E2E SpatiaLite</li><li>Configuration pytest avec support async</li></ul><hr><h2 id="liens" tabindex="-1">Liens <a class="header-anchor" href="#liens" aria-label="Permalink to &quot;Liens&quot;">​</a></h2><ul><li><a href="https://github.com/gispulse/gispulse" target="_blank" rel="noreferrer">Dépôt GitHub</a></li><li><a href="https://github.com/gispulse/gispulse/issues" target="_blank" rel="noreferrer">Signaler un bug</a></li><li><a href="https://github.com/gispulse/gispulse/projects" target="_blank" rel="noreferrer">Roadmap</a></li></ul>',83)])])}const h=o(a,[["render",s]]);export{g as __pageData,h as default};
